async function loadMemoriesCount(){const e=document.querySelector(".quotes-counter-text");if(e)try{const{count:t,error:o}=await supabaseClient.from("memories").select("*",{count:"exact",head:!0}).eq("approved",!0);if(o)throw o;const n=t??0;if(0===n){const e=document.querySelector(".quotes-counter");return void(e&&(e.style.display="none"))}e.textContent=`${n} ${pluralize(n)}`}catch(e){console.error("Не вдалося завантажити кількість спогадів:",e);const t=document.querySelector(".quotes-counter");t&&(t.style.display="none")}}function pluralize(e){if("en"===(document.documentElement.lang||"uk"))return 1===e?"memory":"memories";const t=e%10,o=e%100;return o>=11&&o<=14?"спогадів":1===t?"спогад":t>=2&&t<=4?"спогади":"спогадів"}document.addEventListener("DOMContentLoaded",loadMemoriesCount);